function duplicateZeros(arr) {
    const n = arr.length;
    for (let i = 0; i < n - 1; ++i) {
        if (arr[i] === 0) {
            for (let j = n - 1; j > i + 1; --j) {
                arr[j] = arr[j - 1];
            }
            arr[++i] = 0;
        }
    }
}
